const stdout = items[0].json.stdout || "";

const data = {};
for (const line of stdout.split("\n")) {
  const index = line.indexOf("=");
  if (index === -1) continue;

  const key = line.slice(0, index).trim();
  const value = line.slice(index + 1).trim();
  data[key] = value;
}

const hasDataBackup = Boolean(data.DATA_BACKUP);
const hasDbBackup = Boolean(data.DB_BACKUP);
const hasHtmlBackup = Boolean(data.HTML_BACKUP);
const successLog = Number(data.SUCCESS_LOG || 0) > 0;

const allGood = hasDataBackup && hasDbBackup && hasHtmlBackup && successLog;

const lines = [];

lines.push("🗄️ **Nextcloud Backup Verification**");
lines.push("");
lines.push(`🕒 Time: ${new Date().toLocaleString("en-US", { timeZone: "America/Santo_Domingo" })}`);
lines.push(`🖥️ Host: ${data.HOST || "unknown"}`);
lines.push("");

lines.push(allGood ? "✅ **Backup looks good**" : "🚨 **Backup needs attention**");
lines.push("");

lines.push(`${hasDataBackup ? "✅" : "🚨"} Data backup: ${hasDataBackup ? data.DATA_SIZE || "found" : "missing"}`);
lines.push(`${hasDbBackup ? "✅" : "🚨"} Database backup: ${hasDbBackup ? data.DB_SIZE || "found" : "missing"}`);
lines.push(`${hasHtmlBackup ? "✅" : "🚨"} HTML backup: ${hasHtmlBackup ? data.HTML_SIZE || "found" : "missing"}`);
lines.push(`${successLog ? "✅" : "🚨"} Success message found in log`);
lines.push("");

lines.push("**Latest backup files**");
lines.push("```");
lines.push(`DATA: ${data.DATA_BACKUP || "missing"}`);
lines.push(`DB:   ${data.DB_BACKUP || "missing"}`);
lines.push(`HTML: ${data.HTML_BACKUP || "missing"}`);
lines.push("```");

lines.push("");
lines.push(`💾 Root disk: ${data.DISK_USAGE || "unknown"} used, ${data.DISK_AVAILABLE || "unknown"} available`);

return [
  {
    json: {
      content: lines.join("\n"),
      backupOk: allGood
    }
  }
];
